import{_ as n,C as a,o as s,c,j as e,a as o,E as d,ag as l}from"./chunks/framework.HG0H2VLS.js";const k=JSON.parse('{"title":"ThemeToggle","description":"","frontmatter":{},"headers":[],"relativePath":"components/theme-toggle.md","filePath":"components/theme-toggle.md"}'),h={name:"components/theme-toggle.md"},g={id:"themetoggle",tabindex:"-1"};function m(p,t,u,b,x,f){const r=a("Badge"),i=a("ComponentDemo");return s(),c("div",null,[t[3]||(t[3]=e("hr",null,null,-1)),t[4]||(t[4]=e("h2",{id:"title-themetoggle",tabindex:"-1"},[o("title: ThemeToggle "),e("a",{class:"header-anchor",href:"#title-themetoggle","aria-label":'Permalink to "title: ThemeToggle"'},"​")],-1)),e("h1",g,[t[0]||(t[0]=o("ThemeToggle ",-1)),d(r,{type:"info",text:"Design System"}),t[1]||(t[1]=o()),t[2]||(t[2]=e("a",{class:"header-anchor",href:"#themetoggle","aria-label":'Permalink to "ThemeToggle <Badge type="info" text="Design System" />"'},"​",-1))]),t[5]||(t[5]=e("blockquote",null,[e("p",null,"Inline segmented Light \\")],-1)),d(i,{src:"/demos/src/components/ThemeToggle/ThemeToggle.html"}),t[6]||(t[6]=l('<h2 id="variant-matrix" tabindex="-1">Variant matrix <a class="header-anchor" href="#variant-matrix" aria-label="Permalink to &quot;Variant matrix&quot;">​</a></h2><p>Single axis: <strong>State</strong> = 2 variants.</p><table tabindex="0"><thead><tr><th>Node</th><th>State</th><th>Active button</th></tr></thead><tbody><tr><td><code>2699:2062</code></td><td>Light</td><td>Sun/Light highlighted</td></tr><tr><td><code>2699:2053</code></td><td>Dark</td><td>Moon/Dark highlighted</td></tr></tbody></table><p>The two variants are mirror images. Visual state is driven by <code>aria-pressed</code> on the segment buttons.</p><hr><h2 id="css-class-mapping" tabindex="-1">CSS class mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS class mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma</th><th>CSS</th></tr></thead><tbody><tr><td>Wrapper</td><td><code>.theme-toggle</code> (<code>&lt;div&gt;</code>)</td></tr><tr><td>Fill-parent variant</td><td><code>.theme-toggle--fill</code> (drops the standalone 172px width)</td></tr><tr><td>Light / Dark button</td><td><code>.theme-toggle__btn</code> (<code>&lt;button data-theme-value=&quot;light|dark&quot;&gt;</code>)</td></tr><tr><td>Active state</td><td><code>aria-pressed=&quot;true&quot;</code> on the chosen button</td></tr><tr><td>Sun / Moon icon</td><td><code>&lt;i data-lucide=&quot;sun|moon&quot;&gt;</code></td></tr></tbody></table><hr><h2 id="token-mapping" tabindex="-1">Token mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token mapping&quot;">​</a></h2><h3 id="wrapper" tabindex="-1">Wrapper <a class="header-anchor" href="#wrapper" aria-label="Permalink to &quot;Wrapper&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Background</td><td><code>var(--ai-surface-primary)</code></td></tr><tr><td>Border</td><td><code>1px solid var(--ai-border-secondary)</code></td></tr><tr><td>Border-radius</td><td><code>var(--ai-radius-md)</code> (8px)</td></tr><tr><td>Height</td><td><code>var(--ai-spacing-8)</code> (40px)</td></tr><tr><td>Padding (horizontal)</td><td><code>var(--ai-spacing-1)</code> (4px)</td></tr><tr><td>Gap</td><td><code>0</code></td></tr><tr><td>Width (standalone)</td><td><code>172px</code> (raw — sub-token optical, Figma value)</td></tr></tbody></table><h3 id="segment-buttons" tabindex="-1">Segment buttons <a class="header-anchor" href="#segment-buttons" aria-label="Permalink to &quot;Segment buttons&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Flex</td><td><code>1 0 0</code> (each button fills half)</td></tr><tr><td>Height</td><td><code>var(--ai-spacing-7)</code> (32px)</td></tr><tr><td>Padding (horizontal)</td><td><code>var(--ai-spacing-4)</code> (12px)</td></tr><tr><td>Gap (icon → label)</td><td><code>var(--ai-spacing-3)</code> (8px)</td></tr><tr><td>Background (inactive)</td><td><code>transparent</code></td></tr><tr><td>Background (active)</td><td><code>var(--ai-surface-minimal)</code></td></tr><tr><td>Border</td><td>none</td></tr><tr><td>Border-radius (inactive)</td><td><code>var(--ai-radius-md)</code></td></tr><tr><td>Border-radius (active)</td><td><code>var(--ai-radius-sm)</code></td></tr><tr><td>Text colour</td><td><code>var(--ai-text-primary)</code> (substituted — see Token gaps)</td></tr><tr><td>Font-family</td><td><code>var(--ai-font-body)</code></td></tr><tr><td>Font-weight</td><td><code>var(--ai-font-semibold)</code></td></tr><tr><td>Font-size</td><td><code>var(--ai-font-fluid-xxs)</code> (12px)</td></tr><tr><td>Line-height</td><td><code>var(--ai-leading-xs)</code> (16px)</td></tr><tr><td>Icon size</td><td><code>var(--ai-icon-size-sm)</code> (16px)</td></tr></tbody></table><h3 id="focus" tabindex="-1">Focus <a class="header-anchor" href="#focus" aria-label="Permalink to &quot;Focus&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Outline</td><td><code>2px solid var(--ai-surface-brand); outline-offset: -2px</code></td></tr></tbody></table><hr><h2 id="token-gaps" tabindex="-1">Token gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token gaps&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gap</th><th>Figma value</th><th>Resolution</th></tr></thead><tbody><tr><td>172px (standalone wrapper width)</td><td><code>172px</code></td><td>Approved raw — sub-token optical, Figma value</td></tr><tr><td>Text colour</td><td><code>--ai-btn-tertiary-text</code> (inactive), <code>--ai-btn-secondary-text-hover</code> (active)</td><td>Substituted with <code>--ai-text-primary</code>. Both Figma tokens currently resolve to the same value (#212123). Substitution keeps the semantic cleaner — text colour in a non-button context shouldn&#39;t reference button tokens. Flagged for designer to consider adding <code>--ai-text-on-segment</code> (or similar) if a different value is ever needed.</td></tr></tbody></table><hr><h2 id="interaction-model" tabindex="-1">Interaction model <a class="header-anchor" href="#interaction-model" aria-label="Permalink to &quot;Interaction model&quot;">​</a></h2><p>Click on either segment:</p><ol><li>Flips <code>data-theme=&quot;dark&quot;</code> on <code>&lt;html&gt;</code> (sets for Dark, removes for Light)</li><li>Persists choice to <code>localStorage</code> under key <code>&#39;demo-theme&#39;</code></li><li>Syncs every <code>.theme-toggle</code> on the page (<code>aria-pressed</code> updated)</li><li>Listens for <code>storage</code> events so cross-tab / cross-instance changes propagate</li></ol><p>The localStorage key <code>&#39;demo-theme&#39;</code> is shared with <code>src/components/dark-mode-toggle.js</code> (the demo-page floating gear toolbar) so the two stay in sync if a page uses both.</p><hr><h2 id="cross-context-notes" tabindex="-1">Cross-context notes <a class="header-anchor" href="#cross-context-notes" aria-label="Permalink to &quot;Cross-context notes&quot;">​</a></h2><ul><li><strong>Distinct from <code>dark-mode-toggle.js</code></strong> — that script renders a fixed gear-tab on every demo page (for QA). ThemeToggle is an inline app-level control suitable for embedding inside dropdowns, settings panels, etc. Both control the same underlying <code>data-theme</code> attribute and the same localStorage key.</li><li>Used inside <strong>Dropdown</strong> Type=User menu (<code>src/components/Dropdown/</code>).</li></ul><hr><h2 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h2><ul><li>Each segment is a <code>&lt;button&gt;</code> with <code>aria-pressed</code> reflecting active state.</li><li>Icons have <code>aria-hidden=&quot;true&quot;</code> (the visible label is the accessible name).</li><li>Standalone touch target meets WCAG: 40px wrapper + 32px segment buttons exceed the 24px minimum when paired with surrounding click targets.</li></ul><hr><h2 id="history" tabindex="-1">History <a class="header-anchor" href="#history" aria-label="Permalink to &quot;History&quot;">​</a></h2><ul><li>2026-05-27: Initial scaffold. Built from Figma component set <code>2699:2052</code> (Dropdowns page). Token gaps documented for the 172px standalone width and the button-token-in-non-button-context substitution.</li></ul><h2 id="figma" tabindex="-1">Figma <a class="header-anchor" href="#figma" aria-label="Permalink to &quot;Figma&quot;">​</a></h2><p><a href="https://www.figma.com/design/Lus07xi8pPXLN87sQIyrEt/Affino-AI---Design-System?node-id=2699-2052" target="_blank" rel="noreferrer">Open in Figma</a></p>',34))])}const y=n(h,[["render",m]]);export{k as __pageData,y as default};
